"""K-Nearest Neighbors."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, RegressorMixin


class KNeighborsClassifier(BaseEstimator, ClassifierMixin):
    def __init__(self, n_neighbors=5, *, weights='uniform', algorithm='auto',
                 leaf_size=30, p=2, metric='minkowski', metric_params=None,
                 n_jobs=None):
        self.n_neighbors = n_neighbors
        self.weights = weights
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.p = p
        self.metric = metric
        self.metric_params = metric_params
        self.n_jobs = n_jobs
        self.classes_ = None

    def fit(self, X, y):
        self._X = np.asarray(X, dtype=float)
        self._y = np.asarray(y)
        if self._X.ndim == 1: self._X = self._X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        preds = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            idx = np.argsort(dists)[:self.n_neighbors]
            if self.weights == 'distance':
                w = 1.0 / np.maximum(dists[idx], 1e-10)
                counts = {}
                for i, wi in zip(idx, w):
                    c = self._y[i]
                    counts[c] = counts.get(c, 0) + wi
                preds.append(max(counts, key=counts.get))
            else:
                vals, counts = np.unique(self._y[idx], return_counts=True)
                preds.append(vals[np.argmax(counts)])
        return np.array(preds)


class KNeighborsRegressor(BaseEstimator, RegressorMixin):
    def __init__(self, n_neighbors=5, *, weights='uniform', algorithm='auto',
                 leaf_size=30, p=2, metric='minkowski', metric_params=None,
                 n_jobs=None):
        self.n_neighbors = n_neighbors
        self.weights = weights
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.p = p
        self.metric = metric
        self.metric_params = metric_params
        self.n_jobs = n_jobs

    def fit(self, X, y):
        self._X = np.asarray(X, dtype=float)
        self._y = np.asarray(y, dtype=float)
        if self._X.ndim == 1: self._X = self._X.reshape(-1, 1)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        preds = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            idx = np.argsort(dists)[:self.n_neighbors]
            if self.weights == 'distance':
                w = 1.0 / np.maximum(dists[idx], 1e-10)
                preds.append(np.average(self._y[idx], weights=w))
            else:
                preds.append(np.mean(self._y[idx]))
        return np.array(preds)


# ---------------------------------------------------------------------------
# Radius-based neighbors
# ---------------------------------------------------------------------------

class RadiusNeighborsClassifier(BaseEstimator, ClassifierMixin):
    """Classifier based on neighbors within a fixed radius."""

    def __init__(self, radius=1.0, *, weights='uniform', algorithm='auto',
                 leaf_size=30, p=2, metric='minkowski', outlier_label=None,
                 metric_params=None, n_jobs=None):
        self.radius = radius
        self.weights = weights
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.p = p
        self.metric = metric
        self.outlier_label = outlier_label
        self.metric_params = metric_params
        self.n_jobs = n_jobs
        self.classes_ = None

    def fit(self, X, y):
        self._X = np.asarray(X, dtype=float)
        self._y = np.asarray(y)
        if self._X.ndim == 1:
            self._X = self._X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        preds = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            mask = dists <= self.radius
            if not np.any(mask):
                if self.outlier_label is not None:
                    preds.append(self.outlier_label)
                else:
                    raise ValueError("No neighbors found within radius %f; "
                                     "try increasing the radius or set "
                                     "outlier_label." % self.radius)
                continue
            idx = np.where(mask)[0]
            if self.weights == 'distance':
                w = 1.0 / np.maximum(dists[idx], 1e-10)
                counts = {}
                for i, wi in zip(idx, w):
                    c = self._y[i]
                    counts[c] = counts.get(c, 0) + wi
                preds.append(max(counts, key=counts.get))
            else:
                vals, counts = np.unique(self._y[idx], return_counts=True)
                preds.append(vals[np.argmax(counts)])
        return np.array(preds)


class RadiusNeighborsRegressor(BaseEstimator, RegressorMixin):
    """Regression based on neighbors within a fixed radius."""

    def __init__(self, radius=1.0, *, weights='uniform', algorithm='auto',
                 leaf_size=30, p=2, metric='minkowski', metric_params=None,
                 n_jobs=None):
        self.radius = radius
        self.weights = weights
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.p = p
        self.metric = metric
        self.metric_params = metric_params
        self.n_jobs = n_jobs

    def fit(self, X, y):
        self._X = np.asarray(X, dtype=float)
        self._y = np.asarray(y, dtype=float)
        if self._X.ndim == 1:
            self._X = self._X.reshape(-1, 1)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        preds = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            mask = dists <= self.radius
            if not np.any(mask):
                preds.append(0.0)
                continue
            idx = np.where(mask)[0]
            if self.weights == 'distance':
                w = 1.0 / np.maximum(dists[idx], 1e-10)
                preds.append(np.average(self._y[idx], weights=w))
            else:
                preds.append(np.mean(self._y[idx]))
        return np.array(preds)


# ---------------------------------------------------------------------------
# Unsupervised nearest neighbors
# ---------------------------------------------------------------------------

class NearestNeighbors(BaseEstimator):
    """Unsupervised learner for implementing neighbor searches."""

    def __init__(self, n_neighbors=5, *, radius=1.0, algorithm='auto',
                 leaf_size=30, metric='minkowski', p=2, metric_params=None,
                 n_jobs=None):
        self.n_neighbors = n_neighbors
        self.radius = radius
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.metric = metric
        self.p = p
        self.metric_params = metric_params
        self.n_jobs = n_jobs

    def fit(self, X, y=None):
        self._X = np.asarray(X, dtype=float)
        if self._X.ndim == 1:
            self._X = self._X.reshape(-1, 1)
        self.n_samples_fit_ = self._X.shape[0]
        return self

    def kneighbors(self, X=None, n_neighbors=None, return_distance=True):
        if X is None:
            X = self._X
        else:
            X = np.asarray(X, dtype=float)
            if X.ndim == 1:
                X = X.reshape(-1, 1)
        if n_neighbors is None:
            n_neighbors = self.n_neighbors
        all_dists = []
        all_idx = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            idx = np.argsort(dists)[:n_neighbors]
            all_dists.append(dists[idx])
            all_idx.append(idx)
        distances = np.array(all_dists)
        indices = np.array(all_idx)
        if return_distance:
            return distances, indices
        return indices

    def radius_neighbors(self, X=None, radius=None, return_distance=True):
        if X is None:
            X = self._X
        else:
            X = np.asarray(X, dtype=float)
            if X.ndim == 1:
                X = X.reshape(-1, 1)
        if radius is None:
            radius = self.radius
        all_dists = []
        all_idx = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            mask = dists <= radius
            all_dists.append(dists[mask])
            all_idx.append(np.where(mask)[0])
        if return_distance:
            return all_dists, all_idx
        return all_idx


# ---------------------------------------------------------------------------
# Nearest Centroid
# ---------------------------------------------------------------------------

class NearestCentroid(BaseEstimator, ClassifierMixin):
    """Nearest centroid classifier."""

    def __init__(self, metric='euclidean', shrink_threshold=None):
        self.metric = metric
        self.shrink_threshold = shrink_threshold
        self.classes_ = None
        self.centroids_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        self.centroids_ = np.zeros((len(self.classes_), X.shape[1]))
        for i, c in enumerate(self.classes_):
            mask = y == c
            self.centroids_[i] = X[mask].mean(axis=0)
        if self.shrink_threshold is not None:
            dataset_centroid = X.mean(axis=0)
            for i, c in enumerate(self.classes_):
                n_c = np.sum(y == c)
                deviation = (self.centroids_[i] - dataset_centroid)
                deviation = np.sign(deviation) * np.maximum(
                    np.abs(deviation) - self.shrink_threshold / np.sqrt(n_c), 0
                )
                self.centroids_[i] = dataset_centroid + deviation
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        dists = np.sqrt(((X[:, np.newaxis, :] - self.centroids_[np.newaxis, :, :]) ** 2).sum(axis=2))
        return self.classes_[np.argmin(dists, axis=1)]


# ---------------------------------------------------------------------------
# Local Outlier Factor
# ---------------------------------------------------------------------------

class LocalOutlierFactor(BaseEstimator):
    """Unsupervised outlier detection using Local Outlier Factor (LOF)."""

    def __init__(self, n_neighbors=20, *, algorithm='auto', leaf_size=30,
                 metric='minkowski', p=2, metric_params=None,
                 contamination='auto', novelty=False, n_jobs=None):
        self.n_neighbors = n_neighbors
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.metric = metric
        self.p = p
        self.metric_params = metric_params
        self.contamination = contamination
        self.novelty = novelty
        self.n_jobs = n_jobs

    def _k_distance(self, dists_row, k):
        """Return the k-distance (distance to the k-th nearest neighbor)."""
        sorted_d = np.sort(dists_row)
        # sorted_d[0] is self (0), so k-th neighbor is sorted_d[k]
        return sorted_d[min(k, len(sorted_d) - 1)]

    def _reachability_distance(self, k_dist_b, dist_ab):
        return max(k_dist_b, dist_ab)

    def fit(self, X, y=None):
        self._X = np.asarray(X, dtype=float)
        if self._X.ndim == 1:
            self._X = self._X.reshape(-1, 1)
        n = self._X.shape[0]
        k = min(self.n_neighbors, n - 1)

        # Pairwise distances
        D = np.sqrt(((self._X[:, np.newaxis, :] - self._X[np.newaxis, :, :]) ** 2).sum(axis=2))

        # k-distances
        k_dists = np.zeros(n)
        for i in range(n):
            k_dists[i] = self._k_distance(D[i], k)

        # Local reachability density
        lrd = np.zeros(n)
        for i in range(n):
            nn_idx = np.argsort(D[i])[1:k + 1]
            reach_dists = np.array([self._reachability_distance(k_dists[j], D[i, j])
                                    for j in nn_idx])
            lrd[i] = 1.0 / max(reach_dists.mean(), 1e-10)

        # LOF scores
        lof_scores = np.zeros(n)
        for i in range(n):
            nn_idx = np.argsort(D[i])[1:k + 1]
            lof_scores[i] = np.mean([lrd[j] for j in nn_idx]) / max(lrd[i], 1e-10)

        self.negative_outlier_factor_ = -lof_scores

        # Determine threshold
        if self.contamination == 'auto':
            self.offset_ = -1.5
        else:
            self.offset_ = np.percentile(self.negative_outlier_factor_,
                                         100.0 * self.contamination)
        self.n_features_in_ = self._X.shape[1]
        return self

    def fit_predict(self, X, y=None):
        self.fit(X, y)
        labels = np.ones(self._X.shape[0], dtype=int)
        labels[self.negative_outlier_factor_ < self.offset_] = -1
        return labels

    def predict(self, X):
        """Predict for new data (only available when novelty=True)."""
        if not self.novelty:
            raise ValueError("predict is not available when novelty=False")
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        scores = self.score_samples(X)
        return np.where(scores < self.offset_, -1, 1)

    def score_samples(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_train = self._X.shape[0]
        k = min(self.n_neighbors, n_train)
        D_all = np.sqrt(((self._X[:, np.newaxis, :] - self._X[np.newaxis, :, :]) ** 2).sum(axis=2))
        k_dists_train = np.array([self._k_distance(D_all[i], k) for i in range(n_train)])
        lrd_train = np.zeros(n_train)
        for i in range(n_train):
            nn_idx = np.argsort(D_all[i])[1:k + 1]
            reach_dists = np.array([self._reachability_distance(k_dists_train[j], D_all[i, j])
                                    for j in nn_idx])
            lrd_train[i] = 1.0 / max(reach_dists.mean(), 1e-10)
        scores = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            nn_idx = np.argsort(dists)[:k]
            reach_dists = np.array([self._reachability_distance(k_dists_train[j], dists[j])
                                    for j in nn_idx])
            lrd_x = 1.0 / max(reach_dists.mean(), 1e-10)
            lof = np.mean([lrd_train[j] for j in nn_idx]) / max(lrd_x, 1e-10)
            scores.append(-lof)
        return np.array(scores)


# ---------------------------------------------------------------------------
# Kernel Density Estimation
# ---------------------------------------------------------------------------

class KernelDensity(BaseEstimator):
    """Kernel Density Estimation."""

    def __init__(self, *, bandwidth=1.0, algorithm='auto', kernel='gaussian',
                 metric='euclidean', atol=0, rtol=0, breadth_first=True,
                 leaf_size=40, metric_params=None):
        self.bandwidth = bandwidth
        self.algorithm = algorithm
        self.kernel = kernel
        self.metric = metric
        self.atol = atol
        self.rtol = rtol
        self.breadth_first = breadth_first
        self.leaf_size = leaf_size
        self.metric_params = metric_params

    def fit(self, X, y=None, sample_weight=None):
        self._X = np.asarray(X, dtype=float)
        if self._X.ndim == 1:
            self._X = self._X.reshape(-1, 1)
        self.n_features_in_ = self._X.shape[1]
        return self

    def score_samples(self, X):
        """Compute log-density at each sample in X."""
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = self._X.shape[0]
        d = self._X.shape[1]
        h = self.bandwidth
        log_densities = []
        for x in X:
            dists = np.sqrt(np.sum((self._X - x) ** 2, axis=1))
            if self.kernel == 'gaussian':
                log_k = -0.5 * (dists / h) ** 2
                # log sum exp trick
                max_log_k = np.max(log_k)
                log_density = max_log_k + np.log(np.sum(np.exp(log_k - max_log_k)))
                log_density -= np.log(n) + d * np.log(h) + 0.5 * d * np.log(2 * np.pi)
            elif self.kernel == 'tophat':
                count = np.sum(dists <= h)
                # Volume of d-dimensional ball
                if d == 1:
                    vol = 2 * h
                elif d == 2:
                    vol = np.pi * h ** 2
                else:
                    vol = (np.pi ** (d / 2) / np.math.factorial(int(d / 2))) * h ** d
                log_density = np.log(max(count, 1e-10)) - np.log(n) - np.log(max(vol, 1e-10))
            elif self.kernel == 'epanechnikov':
                u = dists / h
                k_vals = np.where(u <= 1, 0.75 * (1 - u ** 2), 0)
                log_density = np.log(max(np.sum(k_vals), 1e-300)) - np.log(n) - d * np.log(h)
            else:
                # Default to gaussian
                log_k = -0.5 * (dists / h) ** 2
                max_log_k = np.max(log_k)
                log_density = max_log_k + np.log(np.sum(np.exp(log_k - max_log_k)))
                log_density -= np.log(n) + d * np.log(h) + 0.5 * d * np.log(2 * np.pi)
            log_densities.append(log_density)
        return np.array(log_densities)

    def score(self, X, y=None):
        """Compute the total log-likelihood."""
        return np.sum(self.score_samples(X))

    def sample(self, n_samples=1, random_state=None):
        """Generate random samples from the model."""
        rng = np.random.RandomState(random_state)
        n = self._X.shape[0]
        d = self._X.shape[1]
        indices = rng.randint(0, n, size=n_samples)
        samples = self._X[indices].copy()
        if self.kernel == 'gaussian':
            samples += rng.randn(n_samples, d) * self.bandwidth
        elif self.kernel == 'tophat':
            directions = rng.randn(n_samples, d)
            directions /= np.linalg.norm(directions, axis=1, keepdims=True)
            radii = rng.uniform(0, self.bandwidth, size=(n_samples, 1))
            samples += directions * radii
        else:
            samples += rng.randn(n_samples, d) * self.bandwidth
        return samples
